#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    vector<int> zeroes, ones, twos;
    for(int i = 0; i < n; i++) {
        if(nums[i] == 0) zeroes.push_back(nums[i]);
        else if(nums[i] == 1) ones.push_back(nums[i]);
        else twos.push_back(nums[i]);
    }
    for(int i : zeroes) cout << i << ' ';
    for(int i : ones) cout << i << ' ';
    for(int i : twos) cout << i << ' ';
    return 0;
}
